                if dominant[1] / len(name_list) > 0.6:  # 60% 以上
                    conventions.append(
                        ProjectConvention(
                            category=f"naming_{category}",
                            rule=f"Use {dominant[0]}",
                            description=f"{category.replace('_', ' ').title()} should use {dominant[0]}",
                            examples=[
                                n
                                for n in name_list[:3]
                                if dominant[0].replace("_", " ")
                                in self._get_naming_style(n)
                            ],
                            confidence=dominant[1] / len(name_list),
                        )
                    )

        return conventions

    def _get_naming_style(self, name: str) -> str:
        """获取命名风格"""
        if "_" in name and name.islower():
            return "snake case"
        elif name[0].isupper() and "_" not in name:
            return "PascalCase"
        elif name[0].islower() and any(c.isupper() for c in name[1:]):
            return "camelCase"
        elif name.isupper():
            return "UPPER CASE"
        return "other"

    def _analyze_structure_conventions(self) -> List[ProjectConvention]:
        """分析结构约定"""
        conventions = []

        # 检查测试文件位置
        test_patterns = []
        for file_path in self._file_cache.keys():
            if "test" in file_path.lower() or "spec" in file_path.lower():
                path = Path(file_path)
                if "tests" in path.parts or "test" in path.parts:
                    test_patterns.append("separate_dir")
                elif path.stem.endswith(".test") or path.stem.endswith(".spec"):
                    test_patterns.append("colocated")

        if test_patterns:
            dominant = Counter(test_patterns).most_common(1)[0]
            conventions.append(
                ProjectConvention(
                    category="testing",
                    rule=(
                        "Tests in separate directory"
                        if dominant[0] == "separate_dir"
                        else "Tests colocated with source"
                    ),
                    description="Test file organization",
                    examples=[],
                    confidence=dominant[1] / len(test_patterns),
                )
            )

        return conventions

    def _identify_patterns(self):
        """识别设计模式"""
        # 简单的模式识别
        patterns_to_check = [
            (
                "singleton",
                r"(?:getInstance|_instance|__new__)",
                "Singleton pattern detected",
            ),
            (
                "factory",
                r"(?:Factory|create\w+|build\w+)",
                "Factory pattern detected",
            ),
            (
                "observer",
                r"(?:subscribe|addListener|on\(|emit\()",
                "Observer pattern detected",
            ),
            (
                "middleware",
                r"(?:middleware|use\(|next\(\))",
                "Middleware pattern detected",
            ),
            (
                "decorator",
                r"@\w+\s*(?:def|class|function)",
                "Decorator pattern detected",
            ),
        ]

        for content in self._file_cache.values():
            for pattern_name, regex, description in patterns_to_check:
                if re.search(regex, content):
                    existing = next(
                        (p for p in self.patterns if p.name == pattern_name), None
                    )
                    if existing:
                        existing.frequency += 1
                    else:
                        self.patterns.append(
                            CodePattern(
                                name=pattern_name,
                                description=description,
                                pattern=regex,
                                examples=[],
                                frequency=1,
                            )
                        )

    def _analyze_dependencies(self) -> dict:
        """分析依赖关系"""
        dependencies = {}

        # package.json
        pkg_json = self.project_path / "package.json"
        if pkg_json.exists():
            try:
                data = json.loads(pkg_json.read_text())
                dependencies["npm"] = {
                    **data.get("dependencies", {}),
                    **data.get("devDependencies", {}),
                }
            except Exception:
                pass

        # requirements.txt
        reqs = self.project_path / "requirements.txt"
        if reqs.exists():
            try:
                deps = []
                for line in reqs.read_text().splitlines():
                    line = line.strip()
                    if line and not line.startswith("#"):
                        deps.append(line.split("==")[0].split(">=")[0].split("<=")[0])
                dependencies["python"] = deps
            except Exception:
                pass

        # go.mod
        go_mod = self.project_path / "go.mod"
        if go_mod.exists():
            try:
                deps = []
                for line in go_mod.read_text().splitlines():
                    if "\t" in line and not line.startswith(("module", "go ")):
                        deps.append(line.split()[0])
                dependencies["go"] = deps
            except Exception:
                pass

        # 存储依赖知识
        self.knowledge["dependencies:all"] = ProjectKnowledge(
            type=KnowledgeType.DEPENDENCY,
            key="all",
            value=dependencies,
            source="config_files",
        )

        return dependencies

    def _save_all(self):
        """保存所有知识"""
        self._save_knowledge("architecture", self.knowledge)
        self._save_knowledge("patterns", self.patterns)
        self._save_knowledge("conventions", self.conventions)

    def learn_from_interaction(
        self,
        action: str,
        context: dict,
        outcome: str,
    ):
        """
        从交互中学习

        Args:
            action: 执行的动作
            context: 上下文
            outcome: 结果 (success/failure)
        """
        learning = ProjectKnowledge(
            type=KnowledgeType.LEARNING,
            key=f"interaction:{datetime.now().isoformat()}",
            value={
                "action": action,
                "context": context,
                "outcome": outcome,
            },
            source="user_interaction",
        )

        self.knowledge[f"learning:{datetime.now().timestamp()}"] = learning
        self._save_all()

    def get_convention_for(self, category: str) -> Optional[ProjectConvention]:
        """获取特定类别的约定"""
        for conv in self.conventions:
            if conv.category == category:
                return conv
        return None

    def get_patterns(self) -> List[CodePattern]:
        """获取所有模式"""
        return self.patterns

    def generate_claudemd(self) -> str:
        """
        生成 CLAUDE.md 内容

        Returns:
            CLAUDE.md 内容
        """
        lines = [
            f"# {self.project_path.name}",
            "",
            "> Auto-generated by Project Knowledge Learner",
            "",
            "## Project Type",
            "",
        ]

        # 项目类型
        ptype = self.knowledge.get("architecture:type")
        if ptype:
            for t, conf in ptype.value.items():
                if conf > 0.5:
                    lines.append(f"- {t}: {conf:.0%} confidence")

        lines.extend(["", "## Coding Conventions", ""])

        # 约定
        for conv in self.conventions:
            lines.append(f"- **{conv.category}**: {conv.rule}")
            if conv.examples:
                lines.append(f"  - Examples: {', '.join(conv.examples[:3])}")

        lines.extend(["", "## Design Patterns", ""])

        # 模式
        for pattern in self.patterns:
            lines.append(f"- **{pattern.name}**: {pattern.description}")
            lines.append(f"  - Frequency: {pattern.frequency}")

        lines.extend(["", "## Dependencies", ""])

        # 依赖
        deps = self.knowledge.get("dependencies:all")
        if deps:
            for dep_type, dep_list in deps.value.items():
                lines.append(f"### {dep_type.upper()}")
                if isinstance(dep_list, dict):
                    for name, version in list(dep_list.items())[:10]:
                        lines.append(f"- {name}: {version}")
                else:
                    for dep in dep_list[:10]:
                        lines.append(f"- {dep}")

        lines.extend(["", "---", "*This file is auto-generated. Update as needed.*", ""])

        return "\n".join(lines)

    def get_stats(self) -> dict:
        """获取统计信息"""
        return {
            "knowledge_entries": len(self.knowledge),
            "patterns_identified": len(self.patterns),
            "conventions_learned": len(self.conventions),
            "files_analyzed": len(self._file_cache),
        }


# 便捷函数
def learn_project(project_path: Union[str, Path]) -> ProjectKnowledgeLearner:
    """学习项目"""
    learner = ProjectKnowledgeLearner(Path(project_path))
    learner.analyze_project()
    return learner

"""
个性化记忆系统 - 跨会话持久化用户偏好和知识

功能:
- 用户偏好存储
- 常用命令/项目记录
- 错误修复知识库
- 个人工作流学习
- 跨会话上下文恢复

存储位置:
~/.claude/memory/
├── preferences.json      # 用户偏好
├── commands.json         # 常用命令
├── projects.json         # 项目历史
├── error_knowledge.json  # 错误知识库
└── workflows.json        # 工作流模板
"""

import json
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from pathlib import Path
from typing import Any, Optional


class MemoryType(Enum):
    """记忆类型"""

    PREFERENCE = "preference"  # 用户偏好
    COMMAND = "command"  # 命令记录
    PROJECT = "project"  # 项目历史
    ERROR_FIX = "error_fix"  # 错误修复
    WORKFLOW = "workflow"  # 工作流模板
    CONTEXT = "context"  # 会话上下文
    PERMISSION = "permission"  # 权限决策


class PreferenceCategory(Enum):
    """偏好类别"""

    CODING_STYLE = "coding_style"  # 代码风格
    TOOLS = "tools"  # 工具偏好
    LANGUAGE = "language"  # 语言偏好
    WORKFLOW = "workflow"  # 工作流偏好
    OUTPUT = "output"  # 输出格式


@dataclass
class MemoryEntry:
    """记忆条目"""

    id: str
    type: MemoryType
    content: Any
    created_at: datetime
    updated_at: datetime
    access_count: int = 0
    metadata: dict = field(default_factory=dict)

    def to_dict(self) -> dict:
        return {
            "id": self.id,
            "type": self.type.value,
            "content": self.content,
            "created_at": self.created_at.isoformat(),
            "updated_at": self.updated_at.isoformat(),
            "access_count": self.access_count,
            "metadata": self.metadata,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "MemoryEntry":
        return cls(
            id=data["id"],
            type=MemoryType(data["type"]),
            content=data["content"],
            created_at=datetime.fromisoformat(data["created_at"]),
            updated_at=datetime.fromisoformat(data["updated_at"]),
            access_count=data.get("access_count", 0),
            metadata=data.get("metadata", {}),
        )


@dataclass
class UserPreference:
    """用户偏好"""

    category: PreferenceCategory
    key: str
    value: Any
    description: str = ""
    confidence: float = 1.0  # 0-1, 表示偏好确定的程度

    def to_dict(self) -> dict:
        return {
            "category": self.category.value,
            "key": self.key,
            "value": self.value,
            "description": self.description,
            "confidence": self.confidence,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "UserPreference":
        return cls(
            category=PreferenceCategory(data["category"]),
            key=data["key"],
            value=data["value"],
            description=data.get("description", ""),
            confidence=data.get("confidence", 1.0),
        )


@dataclass
class CommandRecord:
    """命令记录"""

    command: str
    frequency: int = 1
    last_used: datetime = field(default_factory=datetime.now)
    success_rate: float = 1.0
    contexts: list[str] = field(default_factory=list)  # 使用场景

    def to_dict(self) -> dict:
        return {
            "command": self.command,
            "frequency": self.frequency,
            "last_used": self.last_used.isoformat(),
            "success_rate": self.success_rate,
            "contexts": self.contexts,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "CommandRecord":
        return cls(
            command=data["command"],
            frequency=data.get("frequency", 1),
            last_used=datetime.fromisoformat(data["last_used"]),
            success_rate=data.get("success_rate", 1.0),
            contexts=data.get("contexts", []),
        )


@dataclass
class ErrorFix:
    """错误修复记录"""

    error_pattern: str  # 错误模式 (正则或关键词)
    error_type: str  # 错误类型
    fix_description: str  # 修复描述
    fix_code: str  # 修复代码
    success_count: int = 1
    fail_count: int = 0
    languages: list[str] = field(default_factory=list)
    created_at: datetime = field(default_factory=datetime.now)

    def to_dict(self) -> dict:
        return {
            "error_pattern": self.error_pattern,
            "error_type": self.error_type,
            "fix_description": self.fix_description,
            "fix_code": self.fix_code,
            "success_count": self.success_count,
            "fail_count": self.fail_count,
            "languages": self.languages,
            "created_at": self.created_at.isoformat(),
        }

    @classmethod
    def from_dict(cls, data: dict) -> "ErrorFix":
        return cls(
            error_pattern=data["error_pattern"],
            error_type=data["error_type"],
            fix_description=data["fix_description"],
            fix_code=data["fix_code"],
            success_count=data.get("success_count", 1),
            fail_count=data.get("fail_count", 0),
            languages=data.get("languages", []),
            created_at=datetime.fromisoformat(data["created_at"]),
        )

    @property
    def success_rate(self) -> float:
        total = self.success_count + self.fail_count
        return self.success_count / total if total > 0 else 0


@dataclass
class PermissionDecision:
    """权限决策记录"""

    permission: str  # 原始权限字符串
    action: str  # "allow" | "deny"
    timestamp: datetime = field(default_factory=datetime.now)
    context: dict = field(default_factory=dict)  # 上下文信息

    def to_dict(self) -> dict:
        return {
            "permission": self.permission,
            "action": self.action,
            "timestamp": self.timestamp.isoformat(),
            "context": self.context,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "PermissionDecision":
        return cls(
            permission=data["permission"],
            action=data["action"],
            timestamp=datetime.fromisoformat(data["timestamp"]),
            context=data.get("context", {}),
        )


@dataclass
class PermissionPattern:
    """权限模式（归纳后的通用模式）"""

    pattern: str  # 通配符模式，如 "Bash(git:*)"
    description: str  # 描述
    count: int = 0  # 使用次数
    examples: list[str] = field(default_factory=list)  # 示例
    first_seen: Optional[datetime] = None
    last_seen: Optional[datetime] = None

    def to_dict(self) -> dict:
        return {
            "pattern": self.pattern,
            "description": self.description,
            "count": self.count,
            "examples": self.examples[:10],  # 最多保留10个示例
            "first_seen": self.first_seen.isoformat() if self.first_seen else None,
            "last_seen": self.last_seen.isoformat() if self.last_seen else None,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "PermissionPattern":
        return cls(
            pattern=data["pattern"],
            description=data.get("description", ""),
            count=data.get("count", 0),
            examples=data.get("examples", []),
            first_seen=datetime.fromisoformat(data["first_seen"])
            if data.get("first_seen") else None,
            last_seen=datetime.fromisoformat(data["last_seen"])
            if data.get("last_seen") else None,
        )


